"""PEP 563 support for MonkeyType.

This module provides transformations to support PEP 563 (Postponed Evaluation
of Annotations) when applying type annotations. This helps avoid circular
import issues by:

1. Adding `from __future__ import annotations` to enable postponed evaluation
2. Moving newly added type imports into `if TYPE_CHECKING:` blocks so they
   are only evaluated during static type checking, not at runtime
"""
from typing import List, Set, Tuple, Union

import libcst as cst


class ImportCollector(cst.CSTVisitor):
    """Collects all `from X import Y` style imports from a module."""

    def __init__(self) -> None:
        self.imports: Set[Tuple[str, str]] = set()

    def _get_module_name(self, node: cst.BaseExpression) -> str:
        if isinstance(node, cst.Name):
            return node.value
        elif isinstance(node, cst.Attribute):
            return self._get_module_name(node.value) + "." + node.attr.value
        return ""

    def visit_ImportFrom(self, node: cst.ImportFrom) -> None:
        if isinstance(node.names, cst.ImportStar):
            return

        module_parts: List[str] = []
        for _ in node.relative:
            module_parts.append(".")

        if node.module:
            module_parts.append(self._get_module_name(node.module))

        module = "".join(module_parts)

        for alias in node.names:
            if isinstance(alias.name, cst.Name):
                self.imports.add((module, alias.name.value))


def collect_imports(module: cst.Module) -> Set[Tuple[str, str]]:
    """Collect all (module, name) imports from a module."""
    wrapper = cst.MetadataWrapper(module)
    collector = ImportCollector()
    wrapper.visit(collector)
    return collector.imports


class Pep563Transformer(cst.CSTTransformer):
    """
    Transforms a module to use PEP 563 postponed annotations.

    This transformer:
    1. Adds `from __future__ import annotations` at the top of the file
    2. Moves newly added imports into an `if TYPE_CHECKING:` block

    This enables type annotations to reference types that would otherwise
    cause circular imports, since the imports are only evaluated during
    static type checking and not at runtime.
    """

    def __init__(self, new_imports: Set[Tuple[str, str]]) -> None:
        super().__init__()
        self.new_imports = new_imports
        self._imports_to_move: List[cst.SimpleStatementLine] = []
        self._has_future_annotations = False
        self._has_type_checking_import = False
        self._has_type_checking_block = False
        self._in_type_checking_block = False

    def _get_module_name(self, node: cst.BaseExpression) -> str:
        if isinstance(node, cst.Name):
            return node.value
        elif isinstance(node, cst.Attribute):
            return self._get_module_name(node.value) + "." + node.attr.value
        return ""

    def _is_future_annotations_import(self, node: cst.ImportFrom) -> bool:
        if not node.module:
            return False
        module_name = self._get_module_name(node.module)
        if module_name != "__future__":
            return False
        if isinstance(node.names, cst.ImportStar):
            return False
        for alias in node.names:
            if isinstance(alias.name, cst.Name) and alias.name.value == "annotations":
                return True
        return False

    def _is_type_checking_import(self, node: cst.ImportFrom) -> bool:
        if not node.module:
            return False
        module_name = self._get_module_name(node.module)
        if module_name != "typing":
            return False
        if isinstance(node.names, cst.ImportStar):
            return False
        for alias in node.names:
            if isinstance(alias.name, cst.Name) and alias.name.value == "TYPE_CHECKING":
                return True
        return False

    def _is_type_checking_block(self, node: cst.If) -> bool:
        return isinstance(node.test, cst.Name) and node.test.value == "TYPE_CHECKING"

    def _get_import_names_to_keep(
        self, node: cst.ImportFrom
    ) -> List[cst.ImportAlias]:
        if isinstance(node.names, cst.ImportStar):
            return []

        module_parts: List[str] = []
        for _ in node.relative:
            module_parts.append(".")
        if node.module:
            module_parts.append(self._get_module_name(node.module))
        module = "".join(module_parts)

        keep = []
        for alias in node.names:
            if isinstance(alias.name, cst.Name):
                if (module, alias.name.value) not in self.new_imports:
                    keep.append(alias)
        return keep

    def _get_import_names_to_move(
        self, node: cst.ImportFrom
    ) -> List[cst.ImportAlias]:
        if isinstance(node.names, cst.ImportStar):
            return []

        module_parts: List[str] = []
        for _ in node.relative:
            module_parts.append(".")
        if node.module:
            module_parts.append(self._get_module_name(node.module))
        module = "".join(module_parts)

        move = []
        for alias in node.names:
            if isinstance(alias.name, cst.Name):
                if (module, alias.name.value) in self.new_imports:
                    move.append(alias)
        return move

    def _make_import_names(
        self, aliases: List[cst.ImportAlias]
    ) -> List[cst.ImportAlias]:
        if len(aliases) == 1:
            return [aliases[0].with_changes(comma=cst.MaybeSentinel.DEFAULT)]
        result = [
            a.with_changes(
                comma=cst.Comma(whitespace_after=cst.SimpleWhitespace(" "))
            )
            for a in aliases[:-1]
        ]
        result.append(aliases[-1].with_changes(comma=cst.MaybeSentinel.DEFAULT))
        return result

    def visit_ImportFrom(self, node: cst.ImportFrom) -> bool:
        if self._is_future_annotations_import(node):
            self._has_future_annotations = True
        if self._is_type_checking_import(node):
            self._has_type_checking_import = True
        return True

    def visit_If(self, node: cst.If) -> bool:
        if self._is_type_checking_block(node):
            self._has_type_checking_block = True
            self._in_type_checking_block = True
        return True

    def leave_If(
        self, original_node: cst.If, updated_node: cst.If
    ) -> Union[cst.If, cst.RemovalSentinel]:
        if self._is_type_checking_block(original_node):
            self._in_type_checking_block = False
            if self._imports_to_move and isinstance(updated_node.body, cst.IndentedBlock):
                all_imports = list(updated_node.body.body) + self._imports_to_move
                new_body = updated_node.body.with_changes(body=all_imports)
                self._imports_to_move = []
                return updated_node.with_changes(body=new_body)
        return updated_node

    def leave_SimpleStatementLine(
        self,
        original_node: cst.SimpleStatementLine,
        updated_node: cst.SimpleStatementLine,
    ) -> Union[cst.SimpleStatementLine, cst.RemovalSentinel]:
        if self._in_type_checking_block:
            return updated_node

        if len(updated_node.body) == 1 and isinstance(
            updated_node.body[0], cst.ImportFrom
        ):
            import_node = updated_node.body[0]
            to_keep = self._get_import_names_to_keep(import_node)
            to_move = self._get_import_names_to_move(import_node)

            if to_move:
                moved_import = import_node.with_changes(
                    names=self._make_import_names(to_move)
                )
                self._imports_to_move.append(
                    cst.SimpleStatementLine(body=[moved_import])
                )

                if not to_keep:
                    return cst.RemovalSentinel.REMOVE
                else:
                    new_import = import_node.with_changes(
                        names=self._make_import_names(to_keep)
                    )
                    return updated_node.with_changes(body=[new_import])

        return updated_node

    def leave_Module(
        self, original_node: cst.Module, updated_node: cst.Module
    ) -> cst.Module:
        if self._has_type_checking_block and not self._imports_to_move:
            if not self._has_future_annotations:
                future_import = cst.SimpleStatementLine(
                    body=[
                        cst.ImportFrom(
                            module=cst.Name("__future__"),
                            names=[cst.ImportAlias(name=cst.Name("annotations"))],
                        )
                    ]
                )
                return updated_node.with_changes(
                    body=[future_import] + list(updated_node.body)
                )
            return updated_node

        if not self._imports_to_move:
            return updated_node

        new_body: List[cst.BaseStatement] = []

        if not self._has_future_annotations:
            future_import = cst.SimpleStatementLine(
                body=[
                    cst.ImportFrom(
                        module=cst.Name("__future__"),
                        names=[cst.ImportAlias(name=cst.Name("annotations"))],
                    )
                ]
            )
            new_body.append(future_import)

        type_checking_block_added = False
        found_first_non_import = False

        for stmt in updated_node.body:
            is_import = isinstance(stmt, cst.SimpleStatementLine) and (
                len(stmt.body) == 1
                and isinstance(stmt.body[0], (cst.Import, cst.ImportFrom))
            )

            if not is_import and not found_first_non_import:
                found_first_non_import = True

                if not self._has_type_checking_import:
                    tc_import = cst.SimpleStatementLine(
                        body=[
                            cst.ImportFrom(
                                module=cst.Name("typing"),
                                names=[cst.ImportAlias(name=cst.Name("TYPE_CHECKING"))],
                            )
                        ],
                        leading_lines=[cst.EmptyLine()],
                    )
                    new_body.append(tc_import)

                tc_block = cst.If(
                    test=cst.Name("TYPE_CHECKING"),
                    body=cst.IndentedBlock(body=self._imports_to_move),
                    leading_lines=[cst.EmptyLine()],
                )
                new_body.append(tc_block)
                type_checking_block_added = True

            new_body.append(stmt)

        if not type_checking_block_added and self._imports_to_move:
            if not self._has_type_checking_import:
                tc_import = cst.SimpleStatementLine(
                    body=[
                        cst.ImportFrom(
                            module=cst.Name("typing"),
                            names=[cst.ImportAlias(name=cst.Name("TYPE_CHECKING"))],
                        )
                    ],
                    leading_lines=[cst.EmptyLine()],
                )
                new_body.append(tc_import)

            tc_block = cst.If(
                test=cst.Name("TYPE_CHECKING"),
                body=cst.IndentedBlock(body=self._imports_to_move),
                leading_lines=[cst.EmptyLine()],
            )
            new_body.append(tc_block)

        return updated_node.with_changes(body=new_body)


def apply_pep563_transform(
    source_module: cst.Module, annotated_module: cst.Module
) -> cst.Module:
    """
    Apply PEP 563 transformation to a module after type annotations have been applied.

    Args:
        source_module: The original source module before annotations were applied.
        annotated_module: The module after annotations have been applied.

    Returns:
        The transformed module with:
        - `from __future__ import annotations` added
        - Newly added type imports moved into `if TYPE_CHECKING:` block
    """
    existing_imports = collect_imports(source_module)
    imports_after = collect_imports(annotated_module)
    new_imports = imports_after - existing_imports

    if not new_imports:
        return annotated_module

    transformer = Pep563Transformer(new_imports)
    return annotated_module.visit(transformer)

def apply_stub_using_libcst(
    stub: str, source: str, overwrite_existing_annotations: bool, pep563: bool = False
) -> str:
    try:
        stub_module = parse_module(stub)
        source_module = parse_module(source)
        context = CodemodContext()
        ApplyTypeAnnotationsVisitor.store_stub_in_context(
            context,
            stub_module,
            overwrite_existing_annotations,
        )
        transformer = ApplyTypeAnnotationsVisitor(context)
        transformed_source_module = transformer.transform_module(source_module)

        if pep563:
            transformed_source_module = apply_pep563_transform(
                source_module, transformed_source_module
            )
    except Exception as exception:
        raise HandlerError(f"Failed applying stub with libcst:\n{exception}")
    return transformed_source_module.code

