        new_body.append(future_import)

    type_checking_block_added = False
    found_first_non_import = False

    for stmt in updated_node.body:
        # Check if this is the existing TYPE_CHECKING block
        if (
            self._added_to_existing_block
            and isinstance(stmt, cst.If)
            and self._is_type_checking_block(stmt)
        ):
            # Add our imports to the existing block
            if isinstance(stmt.body, cst.IndentedBlock):
                all_imports = list(stmt.body.body) + self._imports_to_move
                new_block_body = stmt.body.with_changes(body=all_imports)
                stmt = stmt.with_changes(body=new_block_body)
            type_checking_block_added = True
            new_body.append(stmt)
